query UserCard($id: ID!) {
  user(id: $id) {
    id
    name
    posts(first: 3) {
      title
    }
  }
}

mutation RenameUser($id: ID!, $name: String!) {
  updateUser(id: $id, name: $name) {
    id
    name
  }
}

type User {
  id: ID!
  email: String!
  posts: [Post!]!
}

type Post {
  id: ID!
  title: String!
  author: User!
}
